class Solution:
    def is_valid_tag_name(self, s: str) -> bool:
        if s is None or s == '' return False
        return s.lstrip().startswith('v') and s.lstrip().replace('v', '').replace(' ', '').isalnum() or s.lstrip().startswith('v') and s.lstrip().replace('v', '').replace(' ', '').replace('_', '').replace('-', '').isalnum()
